            justify-content: center;
        }
        .btn {
            font-size: 1.3rem;
        }
        .btn-pink {
            background-color: pink;
            color: #fff;
            transition: all 0.2 ease-in-out;
        }
        .btn-pink:hover {
            background-color: rgb(229, 174, 183);
            color: #fff;
        }
    


